messages.en = { ...messages.en, stayGuide: { title: 'Review how this stay is operated before booking', description: 'This recovery-room-inspired stay keeps pricing accessible by focusing on essential facilities and services. Please review the service scope before booking.', cards: [{ id: 'direct-value', icon: 'price', title: 'Direct booking value', benefitDescription: 'Because reservations are handled directly without OTA platforms, we offer rates at least 15% lower than nearby accommodations.', noteLabel: 'Operation note', noteDescription: 'This booking system and accommodation operations are managed separately from each hospital. Please send booking and stay-related inquiries through this site.' }, { id: 'practical-stay', icon: 'home', title: 'A simple space focused on recovery', benefitDescription: 'This private, practical accommodation focuses on the facilities needed for a simple and comfortable stay before or after surgery.', noteLabel: 'Service scope', noteDescription: 'Hotel-style reception desks and always-on luggage storage are not provided. Check-in and stay guidance are handled contactlessly.' }, { id: 'cleaning-care', icon: 'cleaning', title: 'Professional laundry and cleaning care', benefitDescription: 'Bedding is prepared after high-temperature washing at an in-house laundry facility, and a professional management team maintains key living areas.', noteLabel: 'Cleaning scope', noteDescription: 'As a residential-style stay for daily living and longer visits, cleaning focuses on key spaces such as bedding, bathrooms, and kitchens rather than hotel-style turndown service.' }] } };
messages['zh-CN'] = { ...messages['zh-CN'], stayGuide: { title: '预订前请确认住宿运营方式', description: '这是以必要设施和服务为中心运营、帮助降低价格负担的恢复室概念住宿。预订前请确认服务内容和运营范围。', cards: [{ id: 'direct-value', icon: 'price', title: '直接运营，价格更合理', benefitDescription: '不经过 OTA 平台，由我们直接运营，因此可提供比周边住宿至少低 15% 的价格。', noteLabel: '运营说明', noteDescription: '本住宿预订系统以及住宿运营、管理均与各医院分开进行。住宿预订和使用相关咨询请通过本站提交。' }, { id: 'practical-stay', icon: 'home', title: '可专注恢复的简洁空间', benefitDescription: '这是围绕术前术后停留期间所需设施配置的实用型独立住宿，便于简单、舒适地生活。', noteLabel: '服务范围', noteDescription: '不提供酒店式前台和常设行李寄存服务。入住和住宿使用说明以非面对面方式进行。' }, { id: 'cleaning-care', icon: 'cleaning', title: '专业洗涤与清洁管理', benefitDescription: '床品由自营洗衣工厂高温洗涤后准备，专业管理团队会整理客房的主要生活空间。', noteLabel: '清洁范围', noteDescription: '作为适合长期停留和日常生活的生活型住宿，清洁重点在床品、浴室、厨房等主要生活空间，而非酒店式夜床服务。' }] } };
messages['zh-TW'] = { ...messages['zh-TW'], stayGuide: { title: '預訂前請確認住宿營運方式', description: '這是以必要設施與服務為核心、協助降低價格負擔的恢復室概念住宿。預訂前請先確認服務內容與營運範圍。', cards: [{ id: 'direct-value', icon: 'price', title: '直接營運，價格更合理', benefitDescription: '不經由 OTA 平台，由我們直接營運，因此可提供比周邊住宿至少低 15% 的價格。', noteLabel: '營運說明', noteDescription: '本住宿預訂系統以及住宿營運、管理皆與各醫院分開進行。住宿預訂與使用相關詢問請透過本站提交。' }, { id: 'practical-stay', icon: 'home', title: '可專注恢復的簡潔空間', benefitDescription: '這是以術前術後停留期間所需設施為主所配置的實用型獨立住宿，讓生活更簡單舒適。', noteLabel: '服務範圍', noteDescription: '不提供飯店式櫃檯與常設行李寄放服務。入住與住宿使用說明採非面對面方式進行。' }, { id: 'cleaning-care', icon: 'cleaning', title: '專業洗滌與清潔管理', benefitDescription: '寢具由直營洗衣工廠高溫洗滌後準備，並由專業管理團隊整理客房主要生活空間。', noteLabel: '清潔範圍', noteDescription: '作為適合長期停留與日常生活的生活型住宿，清潔重點在寢具、浴室、廚房等主要生活空間，而非飯店式夜床服務。' }] } };
messages.ja = { ...messages.ja, stayGuide: { title: '予約前に宿泊施設の運営方式をご確認ください', description: '必要な設備とサービスに絞って運営することで、価格負担を抑えた回復室コンセプトの宿泊施設です。予約前にサービス内容と運営範囲をご確認ください。', cards: [{ id: 'direct-value', icon: 'price', title: '直接運営によるより合理的な価格', benefitDescription: 'OTAプラットフォームを介さず直接運営することで、周辺宿泊施設より15%以上低い価格で提供しています。', noteLabel: '運営案内', noteDescription: '本宿泊予約システムおよび宿泊施設の運営・管理は各病院とは別に行われます。宿泊予約や利用に関するお問い合わせは本サイトからお送りください。' }, { id: 'practical-stay', icon: 'home', title: '回復に集中できるシンプルな空間', benefitDescription: '手術前後の滞在中に、複雑さなく快適に過ごせるよう必要な設備を中心に整えた実用的な独立型宿泊施設です。', noteLabel: 'サービス範囲', noteDescription: 'ホテル型のフロントデスクや常時荷物預かりサービスは提供していません。チェックインと施設利用は非対面方式で行われます。' }, { id: 'cleaning-care', icon: 'cleaning', title: '専門的なランドリー・清掃管理', benefitDescription: '直営ランドリー工場で高温洗濯した寝具を用意し、専門管理業者が客室の主要な生活空間を整備します。', noteLabel: '清掃範囲', noteDescription: '長期滞在と日常生活のための生活型宿泊施設として、ホテル式ターンダウンサービスではなく寝具・浴室・キッチンなど主要な生活空間を中心に整備します。' }] } };
messages.th = { ...messages.th, stayGuide: { title: 'โปรดตรวจสอบรูปแบบการให้บริการก่อนจอง', description: 'ที่พักแนวคิดห้องพักฟื้นนี้เน้นสิ่งอำนวยความสะดวกและบริการที่จำเป็น เพื่อช่วยให้ราคาเข้าถึงได้ โปรดตรวจสอบขอบเขตบริการก่อนทำการจอง', cards: [{ id: 'direct-value', icon: 'price', title: 'คุ้มค่าด้วยการจองโดยตรง', benefitDescription: 'เราให้บริการโดยตรงโดยไม่ผ่านแพลตฟอร์ม OTA จึงเสนอราคาต่ำกว่าที่พักใกล้เคียงอย่างน้อย 15%', noteLabel: 'ข้อมูลการให้บริการ', noteDescription: 'ระบบจองและการดูแลที่พักดำเนินการแยกจากแต่ละโรงพยาบาล โปรดส่งคำถามเกี่ยวกับการจองและการเข้าพักผ่านเว็บไซต์นี้' }, { id: 'practical-stay', icon: 'home', title: 'พื้นที่เรียบง่ายเพื่อมุ่งเน้นการพักฟื้น', benefitDescription: 'ที่พักส่วนตัวเชิงใช้งานจริง จัดเตรียมสิ่งอำนวยความสะดวกที่จำเป็นสำหรับการพักก่อนหรือหลังการผ่าตัดอย่างเรียบง่ายและสะดวกสบาย', noteLabel: 'ขอบเขตบริการ', noteDescription: 'ไม่มีเคาน์เตอร์ต้อนรับแบบโรงแรมและบริการรับฝากสัมภาระตลอดเวลา การเช็กอินและคำแนะนำการใช้ที่พักดำเนินการแบบไม่ต้องพบหน้า' }, { id: 'cleaning-care', icon: 'cleaning', title: 'ดูแลซักรีดและทำความสะอาดโดยผู้เชี่ยวชาญ', benefitDescription: 'จัดเตรียมเครื่องนอนที่ซักด้วยอุณหภูมิสูงจากโรงซักรีดในเครือ และมีทีมผู้ดูแลมืออาชีพจัดการพื้นที่ใช้สอยหลักของห้องพัก', noteLabel: 'ขอบเขตการทำความสะอาด', noteDescription: 'ในฐานะที่พักแบบอยู่อาศัยสำหรับการพักระยะยาวและชีวิตประจำวัน การดูแลจะเน้นเครื่องนอน ห้องน้ำ และครัว มากกว่าบริการเปิดเตียงแบบโรงแรม' }] } };
messages.vi = { ...messages.vi, stayGuide: { title: 'Vui lòng xem cách vận hành nơi lưu trú trước khi đặt', description: 'Đây là nơi lưu trú mang khái niệm phòng hồi phục, tập trung vào tiện nghi và dịch vụ cần thiết để giữ chi phí hợp lý. Vui lòng kiểm tra phạm vi dịch vụ trước khi đặt.', cards: [{ id: 'direct-value', icon: 'price', title: 'Giá trị tốt hơn nhờ đặt trực tiếp', benefitDescription: 'Không thông qua nền tảng OTA và được vận hành trực tiếp, nơi lưu trú có mức giá thấp hơn ít nhất 15% so với các chỗ ở lân cận.', noteLabel: 'Thông tin vận hành', noteDescription: 'Hệ thống đặt phòng và việc vận hành, quản lý nơi lưu trú được thực hiện riêng với từng bệnh viện. Vui lòng gửi câu hỏi về đặt phòng và lưu trú qua trang này.' }, { id: 'practical-stay', icon: 'home', title: 'Không gian đơn giản để tập trung hồi phục', benefitDescription: 'Đây là nơi lưu trú độc lập, thực tế, tập trung vào các tiện nghi cần cho thời gian ở trước hoặc sau phẫu thuật một cách đơn giản và thoải mái.', noteLabel: 'Phạm vi dịch vụ', noteDescription: 'Không cung cấp quầy lễ tân kiểu khách sạn hoặc dịch vụ giữ hành lý thường trực. Việc nhận phòng và hướng dẫn sử dụng được thực hiện không tiếp xúc.' }, { id: 'cleaning-care', icon: 'cleaning', title: 'Quản lý giặt là và vệ sinh chuyên nghiệp', benefitDescription: 'Bộ đồ giường được giặt ở nhiệt độ cao tại xưởng giặt trực tiếp, và đội ngũ quản lý chuyên nghiệp chuẩn bị các khu vực sinh hoạt chính trong phòng.', noteLabel: 'Phạm vi vệ sinh', noteDescription: 'Là nơi lưu trú kiểu sinh hoạt cho thời gian ở dài hơn và đời sống hằng ngày, việc vệ sinh tập trung vào bộ đồ giường, phòng tắm, bếp và các khu vực chính thay vì dịch vụ turndown kiểu khách sạn.' }] } };
messages.ru = { ...messages.ru, stayGuide: { title: 'Перед бронированием ознакомьтесь с форматом проживания', description: 'Это жилье с концепцией восстановительной комнаты и акцентом на необходимые удобства и услуги, что помогает сохранять доступную цену. Пожалуйста, заранее проверьте объем предоставляемых услуг.', cards: [{ id: 'direct-value', icon: 'price', title: 'Выгода прямого бронирования', benefitDescription: 'Бронирование обрабатывается напрямую без OTA-платформ, поэтому мы предлагаем цену как минимум на 15% ниже, чем у близлежащих вариантов размещения.', noteLabel: 'Информация о работе', noteDescription: 'Система бронирования, эксплуатация и управление жильем ведутся отдельно от каждой больницы. Вопросы о бронировании и проживании направляйте через этот сайт.' }, { id: 'practical-stay', icon: 'home', title: 'Простое пространство для восстановления', benefitDescription: 'Это отдельное практичное жилье с необходимыми удобствами для простого и комфортного проживания до или после операции.', noteLabel: 'Объем услуг', noteDescription: 'Стойка регистрации гостиничного типа и постоянное хранение багажа не предоставляются. Заезд и инструкции по проживанию организованы бесконтактно.' }, { id: 'cleaning-care', icon: 'cleaning', title: 'Профессиональная стирка и уборка', benefitDescription: 'Постельные принадлежности проходят высокотемпературную стирку на собственной прачечной, а профессиональная команда обслуживает основные жилые зоны.', noteLabel: 'Объем уборки', noteDescription: 'Как жилье для повседневного и более длительного проживания, уборка сосредоточена на постельных принадлежностях, ванной, кухне и ключевых зонах, а не на гостиничном turndown-сервисе.' }] } };

messages.ko = { ...messages.ko, guide: { ...messages.ko.guide, items: [{ title: '비대면 체크인', description: '체크인은 비대면으로 진행됩니다. 체크인 당일 객실 출입용 PIN code가 안내됩니다. 객실에 방문하여 이 PIN code를 직접 입력하고 바로 체크인하면 됩니다.' }, { title: '객실 내 금연', description: '객실 내부는 전 구역 금연입니다. 흡연으로 인한 냄새, 오염 또는 시설 손상이 확인되면 추가 비용이 발생할 수 있습니다.' }, { title: '과도한 소음 금지', description: '다른 이용객과 인근 거주자를 위해 늦은 시간에는 소음을 줄여 주세요.' }, { title: '취사 및 주방 이용', description: '객실 내 간단한 취사가 가능합니다. 조리 후에는 화재 예방을 위해 하이라이트와 전기기기의 전원이 꺼졌는지 확인해 주세요.' }, { title: '쓰레기 처리', description: '재활용(캔, 유리, 플라스틱, 종이박스) 쓰레기는 G2층 주차장 안쪽 쓰레기장에 버려주세요. 일반쓰레기는 흰색/보라색 일반쓰레기봉투에, 음식물 쓰레기는 파란색/노란색 음식물 쓰레기봉투에 담아 L1층 출입문 바깥 왼쪽 컨테이너에 버려주세요.' }, { title: '파손 및 오염', description: '객실 시설이나 비품이 파손되거나 일반적인 청소 범위를 초과하는 오염이 발생한 경우 실제 처리 비용이 청구될 수 있습니다.' }, { title: '주차 안내', description: '주차는 지원되지 않습니다. 근처 공영주차장 이용을 권장드립니다.' }, { title: '병원 일정과 숙박 일정', description: '병원 진료, 검사, 수술 또는 퇴원 일정과 숙소 예약은 별도로 관리됩니다. 병원 일정이 변경되더라도 숙소 예약 및 환불 정책은 별도로 적용됩니다.' }, { title: '응급상황 안내', description: '본 숙소는 의료기관이나 응급의료시설이 아닙니다. 응급상황 발생 시 즉시 이용 중인 의료기관에 연락해 주세요.' }] } };
messages.en = { ...messages.en, guide: { ...messages.en.guide, items: [{ title: 'Contactless check-in', description: 'Check-in is contactless. On the check-in day, a PIN code for room access will be provided. Visit the room, enter the PIN code yourself, and check in directly.' }, { title: 'No smoking', description: 'All indoor areas are non-smoking. Additional costs may apply for odor, contamination, or facility damage caused by smoking.' }, { title: 'Noise', description: 'Please keep noise down during late hours for other guests and nearby residents.' }, { title: 'Kitchen use', description: 'Light cooking is allowed. After cooking, check that the cooktop and electric appliances are turned off.' }, { title: 'Waste disposal', description: 'Please dispose of recyclables (cans, glass, plastic, and cardboard boxes) at the waste area inside the G2 parking level. Put general waste in white/purple general waste bags and food waste in blue/yellow food waste bags, then place them in the container outside the L1 entrance on the left.' }, { title: 'Damage and stains', description: 'Actual handling costs may be charged for damaged facilities or contamination beyond normal cleaning.' }, { title: 'Parking', description: 'Parking is not provided. We recommend using a nearby public parking lot.' }, { title: 'Hospital schedule', description: 'Hospital appointments, tests, surgery, discharge, and accommodation reservations are managed separately. Accommodation booking and refund policies apply separately even if hospital schedules change.' }, { title: 'Emergency', description: 'This accommodation is not a medical or emergency care facility. In an emergency, contact the medical institution you are using immediately.' }] } };
messages['zh-CN'] = { ...messages['zh-CN'], guide: { ...messages['zh-CN'].guide, items: [{ title: '非面对面入住', description: '入住采用非面对面方式。入住当天将提供客房出入用 PIN code。到达客房后，请自行输入该 PIN code 并直接入住。' }, { title: '室内禁烟', description: '客房内部全区域禁烟。如因吸烟产生异味、污染或设施损坏，可能产生额外费用。' }, { title: '避免过度噪音', description: '为了其他住客和附近居民，请在较晚时段降低噪音。' }, { title: '烹饪及厨房使用', description: '客房内可进行简单烹饪。烹饪后请确认电陶炉和电器电源已关闭，以预防火灾。' }, { title: '垃圾处理', description: '可回收垃圾（罐、玻璃、塑料、纸箱）请丢弃至 G2 层停车场内侧垃圾点。一般垃圾请装入白色/紫色一般垃圾袋，厨余垃圾请装入蓝色/黄色厨余垃圾袋，并放至 L1 层出入口外左侧集装箱。' }, { title: '损坏及污染', description: '如客房设施或备品损坏，或出现超出一般清洁范围的污染，可能会收取实际处理费用。' }, { title: '停车说明', description: '不提供停车支持。建议使用附近公共停车场。' }, { title: '医院日程与住宿日程', description: '医院诊疗、检查、手术或出院日程与住宿预订分开管理。即使医院日程发生变化，住宿预订和退款政策也将另行适用。' }, { title: '紧急情况说明', description: '本住宿不是医疗机构或急救医疗设施。发生紧急情况时，请立即联系您正在使用的医疗机构。' }] } };
messages['zh-TW'] = { ...messages['zh-TW'], guide: { ...messages['zh-TW'].guide, items: [{ title: '非面對面入住', description: '入住採非面對面方式。入住當天將提供客房出入用 PIN code。抵達客房後，請自行輸入該 PIN code 並直接入住。' }, { title: '室內禁菸', description: '客房內全區禁菸。如因吸菸產生異味、污染或設施損壞，可能會產生額外費用。' }, { title: '避免過度噪音', description: '為了其他住客與附近居民，請在較晚時段降低音量。' }, { title: '烹飪與廚房使用', description: '客房內可進行簡單烹飪。烹飪後請確認電陶爐與電器電源已關閉，以預防火災。' }, { title: '垃圾處理', description: '可回收垃圾（罐、玻璃、塑膠、紙箱）請丟至 G2 層停車場內側垃圾區。一般垃圾請裝入白色/紫色一般垃圾袋，廚餘垃圾請裝入藍色/黃色廚餘垃圾袋，並放至 L1 層出入口外左側貨櫃。' }, { title: '損壞與污染', description: '若客房設施或備品損壞，或出現超出一般清潔範圍的污染，可能會收取實際處理費用。' }, { title: '停車說明', description: '不提供停車支援。建議使用附近公共停車場。' }, { title: '醫院日程與住宿日程', description: '醫院診療、檢查、手術或出院日程與住宿預訂分開管理。即使醫院日程變更，住宿預訂與退款政策仍會另行適用。' }, { title: '緊急情況說明', description: '本住宿不是醫療機構或急救醫療設施。發生緊急情況時，請立即聯絡您正在使用的醫療機構。' }] } };
messages.ja = { ...messages.ja, guide: { ...messages.ja.guide, items: [{ title: '非対面チェックイン', description: 'チェックインは非対面で行われます。チェックイン当日に客室入室用のPIN codeをご案内します。客室に到着後、そのPIN codeを直接入力してそのままチェックインしてください。' }, { title: '客室内禁煙', description: '客室内は全エリア禁煙です。喫煙による臭い、汚れ、設備損傷が確認された場合、追加費用が発生することがあります。' }, { title: '過度な騒音の禁止', description: '他の利用者と近隣住民のため、遅い時間帯は音を控えてください。' }, { title: '調理・キッチン利用', description: '客室内で簡単な調理が可能です。調理後は火災予防のため、コンロと電気機器の電源が切れているか確認してください。' }, { title: 'ゴミ処理', description: 'リサイクル（缶、ガラス、プラスチック、段ボール）ゴミはG2階駐車場内側のゴミ置き場に捨ててください。一般ゴミは白/紫の一般ゴミ袋に、生ゴミは青/黄色の生ゴミ袋に入れ、L1階出入口の外、左側のコンテナに捨ててください。' }, { title: '破損・汚損', description: '客室設備や備品が破損した場合、または通常清掃の範囲を超える汚損が発生した場合、実費を請求することがあります。' }, { title: '駐車案内', description: '駐車場は提供していません。近隣の公共駐車場の利用をおすすめします。' }, { title: '病院日程と宿泊日程', description: '病院の診療、検査、手術、退院日程と宿泊予約は別々に管理されます。病院日程が変更されても、宿泊予約と返金ポリシーは別途適用されます。' }, { title: '緊急時の案内', description: '本宿泊施設は医療機関または救急医療施設ではありません。緊急時は直ちに利用中の医療機関へ連絡してください。' }] } };
messages.th = { ...messages.th, guide: { ...messages.th.guide, items: [{ title: 'เช็กอินแบบไม่พบหน้า', description: 'การเช็กอินดำเนินการแบบไม่พบหน้า ในวันเช็กอินจะมีการแจ้ง PIN code สำหรับเข้าห้องพัก เมื่อมาถึงห้องพัก ให้กรอก PIN code ด้วยตนเองและเช็กอินได้ทันที' }, { title: 'งดสูบบุหรี่ในห้องพัก', description: 'พื้นที่ภายในห้องพักทั้งหมดเป็นเขตปลอดบุหรี่ หากพบกลิ่น คราบ หรือความเสียหายจากการสูบบุหรี่ อาจมีค่าใช้จ่ายเพิ่มเติม' }, { title: 'งดใช้เสียงดังเกินควร', description: 'โปรดลดเสียงในช่วงเวลาดึกเพื่อผู้เข้าพักท่านอื่นและผู้อยู่อาศัยใกล้เคียง' }, { title: 'การทำอาหารและใช้ครัว', description: 'สามารถทำอาหารง่าย ๆ ภายในห้องพักได้ หลังใช้งานโปรดตรวจสอบว่าเตาและเครื่องใช้ไฟฟ้าปิดแล้วเพื่อป้องกันอัคคีภัย' }, { title: 'การทิ้งขยะ', description: 'ขยะรีไซเคิล (กระป๋อง แก้ว พลาสติก และกล่องกระดาษ) โปรดทิ้งที่จุดทิ้งขยะด้านในลานจอดรถชั้น G2 ขยะทั่วไปให้ใส่ถุงขยะทั่วไปสีขาว/ม่วง และขยะอาหารให้ใส่ถุงขยะอาหารสีน้ำเงิน/เหลือง แล้วนำไปไว้ในคอนเทนเนอร์ด้านซ้ายนอกประตูทางเข้าชั้น L1' }, { title: 'ความเสียหายและคราบสกปรก', description: 'หากสิ่งอำนวยความสะดวกหรือของใช้ในห้องพักเสียหาย หรือมีคราบเกินขอบเขตการทำความสะอาดปกติ อาจมีการเรียกเก็บค่าใช้จ่ายตามจริง' }, { title: 'ที่จอดรถ', description: 'ไม่มีบริการที่จอดรถ แนะนำให้ใช้ที่จอดรถสาธารณะใกล้เคียง' }, { title: 'ตารางโรงพยาบาลและการเข้าพัก', description: 'นัดหมาย การตรวจ การผ่าตัด หรือกำหนดออกจากโรงพยาบาล และการจองที่พักได้รับการจัดการแยกกัน แม้ตารางโรงพยาบาลเปลี่ยนแปลง นโยบายการจองและคืนเงินของที่พักยังคงแยกต่างหาก' }, { title: 'กรณีฉุกเฉิน', description: 'ที่พักนี้ไม่ใช่สถานพยาบาลหรือสถานที่รักษาฉุกเฉิน หากเกิดเหตุฉุกเฉิน โปรดติดต่อสถานพยาบาลที่ท่านใช้บริการทันที' }] } };
messages.vi = { ...messages.vi, guide: { ...messages.vi.guide, items: [{ title: 'Nhận phòng không tiếp xúc', description: 'Việc nhận phòng được thực hiện không tiếp xúc. Vào ngày nhận phòng, PIN code để vào phòng sẽ được gửi. Khi đến phòng, bạn tự nhập PIN code này và nhận phòng ngay.' }, { title: 'Không hút thuốc trong phòng', description: 'Toàn bộ khu vực bên trong phòng là không hút thuốc. Nếu phát hiện mùi, vết bẩn hoặc hư hỏng do hút thuốc, có thể phát sinh chi phí bổ sung.' }, { title: 'Không gây tiếng ồn quá mức', description: 'Vui lòng giảm tiếng ồn vào giờ muộn để không ảnh hưởng đến khách khác và cư dân lân cận.' }, { title: 'Nấu ăn và sử dụng bếp', description: 'Bạn có thể nấu ăn đơn giản trong phòng. Sau khi nấu, vui lòng kiểm tra bếp và thiết bị điện đã tắt để phòng cháy.' }, { title: 'Xử lý rác', description: 'Rác tái chế (lon, thủy tinh, nhựa, thùng giấy) vui lòng bỏ tại khu rác phía trong bãi đỗ xe tầng G2. Rác thường cho vào túi rác thường màu trắng/tím, rác thực phẩm cho vào túi rác thực phẩm màu xanh dương/vàng, rồi đặt trong container bên trái ngoài cửa ra vào tầng L1.' }, { title: 'Hư hỏng và vết bẩn', description: 'Nếu cơ sở vật chất hoặc vật dụng trong phòng bị hư hỏng, hoặc có vết bẩn vượt quá phạm vi vệ sinh thông thường, chi phí xử lý thực tế có thể được tính thêm.' }, { title: 'Đỗ xe', description: 'Không hỗ trợ đỗ xe. Chúng tôi khuyến nghị sử dụng bãi đỗ xe công cộng gần đó.' }, { title: 'Lịch bệnh viện và lịch lưu trú', description: 'Lịch khám, xét nghiệm, phẫu thuật hoặc xuất viện của bệnh viện và đặt phòng lưu trú được quản lý riêng. Ngay cả khi lịch bệnh viện thay đổi, chính sách đặt phòng và hoàn tiền của nơi lưu trú vẫn áp dụng riêng.' }, { title: 'Trường hợp khẩn cấp', description: 'Nơi lưu trú này không phải là cơ sở y tế hoặc cơ sở cấp cứu. Khi xảy ra trường hợp khẩn cấp, vui lòng liên hệ ngay với cơ sở y tế bạn đang sử dụng.' }] } };
messages.ru = { ...messages.ru, guide: { ...messages.ru.guide, items: [{ title: 'Бесконтактный заезд', description: 'Заезд проходит бесконтактно. В день заезда будет предоставлен PIN code для доступа в номер. Придите в номер, самостоятельно введите этот PIN code и сразу заселяйтесь.' }, { title: 'Курение в номере запрещено', description: 'Все внутренние помещения номера являются зоной без курения. За запах, загрязнение или повреждение помещений из-за курения могут взиматься дополнительные расходы.' }, { title: 'Избегайте чрезмерного шума', description: 'Пожалуйста, снижайте уровень шума в позднее время ради других гостей и соседних жителей.' }, { title: 'Готовка и использование кухни', description: 'В номере разрешена простая готовка. После приготовления проверьте, что плита и электрические приборы выключены для предотвращения пожара.' }, { title: 'Вынос мусора', description: 'Перерабатываемый мусор (банки, стекло, пластик и картонные коробки) выбрасывайте в мусорной зоне внутри парковки на этаже G2. Обычный мусор положите в белые/фиолетовые пакеты для обычного мусора, пищевые отходы — в синие/желтые пакеты для пищевых отходов, затем оставьте их в контейнере слева снаружи входа на этаже L1.' }, { title: 'Повреждения и загрязнения', description: 'При повреждении оборудования или вещей в номере, а также при загрязнении сверх обычной уборки, могут быть взысканы фактические расходы на обработку.' }, { title: 'Парковка', description: 'Парковка не предоставляется. Рекомендуем пользоваться ближайшей общественной парковкой.' }, { title: 'Расписание больницы и проживания', description: 'Приемы, обследования, операции, выписка и бронирование проживания управляются отдельно. Даже при изменении расписания больницы правила бронирования и возврата за проживание применяются отдельно.' }, { title: 'Экстренная ситуация', description: 'Это жилье не является медицинским учреждением или учреждением неотложной помощи. В экстренной ситуации немедленно свяжитесь с медицинским учреждением, которым вы пользуетесь.' }] } };


